    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '5', '', '', 'E-Book Reader werden immer beliebter. Auch wenn Menschen sich nur langsam vonsphysischen Büchern trennen wollen, so hat eine Umfrage der deutschen Verlagswesensskürzlich gezeigt, dass ein potenzieller Käufer eines E-Book-Readers bis zu zwei Jahreslang erwägt sich ein digitales Lesegerät anzuschaffen. Jedoch kaufen diejenigen, die sichseinmal gegen die Papierform des Buchs entscheiden auch meistens nur noch diesdigitalen Buchversionen. Der Buchmarkt erlebt dadurch ein Hoch - denn die Kauflustssteigt enorm, wenn man mit einem Klick das Buch haben kann, anstatt zum Buchladenszu gehen, oder auf die Lieferung zu warten.', '') RETURNING id INTO new_question_id;
