    INSERT INTO test_parts (test_id, title, part_type) VALUES (new_test_id, 'Lesen Sie den Text und beantworten Sie anschließend die Fragen auf der nächsten Seite. Die Aufgaben haben manchmal eine andere Reihenfolge als die Informationen im Text.', 'textAndMultipleChoice') RETURNING id INTO new_part_id;
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '', 'Um 10 Uhr kommt Joschi ins Büro. An der Rezeption gibt er an einem Computer an,sdass er da ist. Nach einem netten Plausch mit seiner Kollegin Ina, geht er an seinen Platzsund packt seinen Laptop aus. Joshi ist 34 und Softwareingeneur. Ina, seinesTischnachbarin ist Grafikerin und baut heute ihre Webseite neu. Beide könnten ebensosgut zu Hause bleiben, anstatt in ein Büro zu gehen.<br></br>Dank Internet und der Möglichkeit über Chats und andere Kommunikationsprogrammesmit Kollegen am anderen Ende der Welt permament verbunden zu sein, könnten vielesMenschen heutzutage einfach zu Hause bleiben. Doch obwohl immer mehr Jobs keinesPräsenz mehr an einem bestimmten Arbeitsort verlangen, finden sich immer mehrsMenschen im Coworking Spaces zusammen. Besonders in Großstädten werden immersmehr solcher Gemeinschaften gegründet. Viele werden dabei nicht nur tagsüber alssBüros genutzt, sondern auch abends für Veranstaltungen.<br>s“Wir haben unseren Coworking Space gegründet, weil wir kreative Menschenszusammenbringen wollen”s, sagt Gabriel Moss, Gründer der Bürogemeinschaft.s“Gerade,swenn man in unterschiedlichen Branchen arbeitet, kann ein Austausch sehr erfrischendssein. Aber wir möchten auch aktiv etwas für die Kultur tun und veranstalten Konzerte insunseren Räumen und vermieten sie auch für andere Events an andere, um Geldsreinzuholen.s”<br>sJosha und Ina machen in der Küche eine Pause. Gérome, ein Koch, beginnt geradesGemüse klein zu schneiden. Einmal pro Woche wird nämlich für alle gekocht und auchsGäste, also solche, die noch keinen Platz in der NOIZE FABRIK haben, sind eingeladen,smitzuspeisen.<br>s“Bevor ich mir einen Platz gemietet habe, habe ich hier erstmal mit den Leuten zusMittag gegessen. Ich wollte sie erstmal kennenlernen, bevor ich mich entscheide, jedensTag unter ihnen zu sein”s, sagt Josha,s“ich bin heilfroh, dass ich mich so schnell hierseingefunden habe. Zu Hause ist mir die Decke auf den Kopf gefallen.s”', 'Eine neue Arbeitswelt: Coworking Spaces', 'Immer mehr Menschen suchen eine kreative Bürogemeinschaft - wie in der NOIZE FABRIK in Berlin', '');
    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '6', '', '', 'Für immer mehr Jobs heutzutage', '') RETURNING id INTO new_question_id;
