    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '3', '', '', 'Freizeit auf dem Wasser muss nicht teuer sein. Viele Freizeitsportler wissen nicht, wiesgünstig beispielsweise ein Segelkurs sein kann. Während einige Segelschulen bis zus1000 € für einen Segelschein verlangen, kann man schon für wenige hundert Euro ansden deutschen Universitäten auf seine Kosten kommen. Wer sich auf die Suche machtsund die Anmeldungstermine auf den Seiten des Hochschulsports beachtet, sitztsvielleicht schon bald mit Studenten in einem Boot und setzt die Segel. Für Mitgliedersbieten Unis auch günstigen Bootsverleih an.', '') RETURNING id INTO new_question_id;
