    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '4', '', '', 'Bildungsforscher alarmieren: immer mehr Grundschulen müssen ihresLeistungsmaßstäbe heruntersetzen. Kurzfristig wollen sie damit ihre Erfolgsquotenshalten - welche Schule brüstet sich schon damit, dass 20 % der Schüler ein Jahrsnachholen müssen. Es ist nachvollziehbar, dass Schulen mehr Erfolg “generieren”swollen, indem sie immer weniger von dern Schülern verlangen. Langfristig wird damitsjedoch ein großes Bildungsloch bei einer Generation gegraben, die eh schon sehr kleinsist.', '') RETURNING id INTO new_question_id;
