    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '14', 'Ihre Arbeitskollegin hat ein leidenschaftiches Hobby: sie stellt Schmuck aus Metall her. Sie würde gerne etwas verkaufen, aber sie weiß nicht wo.', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '15', 'Seit seinem Burnout als Broker interessiert sich ihr Freund für Meditation. Er möchte auch anderen Menschen Meditation beibringen. Vielleicht haben Sie einen Tipp für ihn?', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '16', 'Ihre Nachbarin möchte ein besserer Mensch werden und erzählt Ihnen, dass sie sich gerne sozial engagieren möchte. Vielleicht haben Sie eine Idee, wo sie beginnen könnte?', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '17', 'Ein Freund von Ihnen sucht einen gebrauchten Computer. Er hat nicht viel Geld, deshalb darf der Computer nicht viel kosten.', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '18', 'Sie sind gerade nach Berlin gezogen und brauchen Hilfe bei der Anmeldung und Wohnungsfindung.', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '19', 'Sie besitzen einen alten Laptop. Er funktioniert noch, aber er ist nichts mehr wert. Sie wollen ihn trotzdem nicht wegschmeißen.', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, '20', 'Ihr Nachbar lebt allein und fühlt sich einsam. Er hätte gerne einen Hund, aber für ihn alleine ist es auf Dauer zu viel Arbeit.', '', '', '');
