    INSERT INTO test_parts (test_id, title, part_type) VALUES (new_test_id, 'Lesen Sie die Überschriften A-J und anschließend die Texte auf der nächsten Seite. Ordnen Sie dann jedem Text die passende Überschrift zu. Jede Überschrift dürfen Sie nur einmal benutzen.', 'decriptionAndText') RETURNING id INTO new_part_id;
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'A', 'Wassersport: Teures Hobby - günstiger Einstieg', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'B', 'Digitales Lesen treibt den Buchverkauf an', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'C', 'Mehr Zeit zum Lesen: Die Regierung verordnet mehr Lesezeit in Schulen', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'D', 'Mit weniger Kaffee mehr vom Leben - Programme gegen die Sucht', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'E', 'Worauf sie beim Fahrradkauf achten sollten', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'F', 'Mehr Urlaubstage für Arbeitnehmer', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'G', 'Warum auf die Malediven fliegen? In Deutschland ist’s doch genauso schön.', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'H', 'Gefährliche Cyborgs: immer weniger Menschen denken selbst', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'I', 'Bildung in Not: Warum unsere Kinder immer weniger in den Grundschulen lernen', '', '', '');
    INSERT INTO descriptions (test_part_id, idx, text, header, subheader, image) VALUES (new_part_id, 'J', 'Mopsdiebstahl in der Stadt - Eine Autorin referiert über effiziente Kommunikation', '', '', '');
    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '1', '', '', 'Wenn es um Drogen geht, denkt man gleich an Kokain, Marihuana, doch wenigensKonsumenten ist bewusst: die weltweit am meisten verbreitete und akzeptierte Drogesist Koffein. Viele Menschen unterschätzen die Suchtwirkung des braunen Gebräus.sTatsächlich sagen 8 von zehn Kaffeetrinkern, es würde ihnen schwer fallen, von heutesauf morgen keinen Kaffee mehr zu trinken. Das Bundesgesundheitsministerium startetseine Aufklärungskampagne zur Entwöhnung und zur gesunden Lebensgestaltung undsveranstaltet eine Vortragsreihe mit Medizinern und Ernährungsexperten.', '') RETURNING id INTO new_question_id;
