    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '1', '', '', 'Wenn es um Drogen geht, denkt man gleich an Kokain, Marihuana, doch wenigensKonsumenten ist bewusst: die weltweit am meisten verbreitete und akzeptierte Drogesist Koffein. Viele Menschen unterschätzen die Suchtwirkung des braunen Gebräus.sTatsächlich sagen 8 von zehn Kaffeetrinkern, es würde ihnen schwer fallen, von heutesauf morgen keinen Kaffee mehr zu trinken. Das Bundesgesundheitsministerium startetseine Aufklärungskampagne zur Entwöhnung und zur gesunden Lebensgestaltung undsveranstaltet eine Vortragsreihe mit Medizinern und Ernährungsexperten.', '') RETURNING id INTO new_question_id;
