    INSERT INTO questions (test_part_id, idx, header, subheader, text, image) VALUES (new_part_id, '2', '', '', 'Trotz erschwinglicher Flugpreise, mittlerweile auch für Flüge in Überseegebiete,sbevorzugen es immer mehr Menschen in Deutschland, Urlaub im eigenen Land zusmachen. Bisher wurden Urlaubsziele in Brandenburg, im Harz und im Schwarzwaldsunterschätzt. Umso mehr steigt jetzt deren Attraktivität insbesondere bei unters40-jährigen, die sich immer mehr als Entdecker der heimischen Natur- undsKulturlandschaft betrachten. Im Vergleich mit Urlaubsfotos aus den Malediven steht diesBrandenburgische Seenplatte in nichts nach.', '') RETURNING id INTO new_question_id;
